    25→interface Project {
    26→    id: string;
    27→    title?: string;
    28→    text: string;
    29→    description?: string;
    30→    color?: string;
    31→    globalScore?: number;
    32→    recommendation?: string;
    33→    confidenceLevel?: string;
    34→    viabilityScore?: number;
    35→    classification?: string;
    36→    timestamp: string;
