    43→const DECISION_FILTERS = ["GO", "EXPLORE", "PARK", "KILL"] as const;
    44→
    45→const DECISION_COLORS: Record<string, { bg: string; text: string; border: string }> = {
    46→    GO: { bg: "bg-emerald-500/10", text: "text-emerald-400", border: "border-emerald-500/30" },
    47→    EXPLORE: { bg: "bg-amber-500/10", text: "text-amber-400", border: "border-amber-500/30" },
    48→    PARK: { bg: "bg-gray-500/10", text: "text-gray-400", border: "border-gray-500/30" },
    49→    KILL: { bg: "bg-red-500/10", text: "text-red-400", border: "border-red-500/30" },
    50→};
    51→
    52→function getProjectScore(p: Project): number | undefined {
    53→    return p.globalScore ?? p.viabilityScore;
    54→}
    55→
    56→function getProjectDecision(p: Project): string {
    57→    return p.recommendation ?? p.classification ?? "DRAFT";
    58→}
    59→
    60→function getProjectTitle(p: Project): string {
    61→    return p.title ?? p.text;
    62→}
    63→
    64→function getProjectColor(p: Project): string {
    65→    if (p.color) return p.color;
    66→    const decision = getProjectDecision(p);
    67→    switch (decision) {
    68→        case "GO": return "#10B981";
    69→        case "EXPLORE": return "#F59E0B";
    70→        case "PARK": return "#6B7280";
    71→        case "KILL": return "#EF4444";
    72→        default: return "#6B7280";
    73→    }
    74→}
    75→
    76→function getScoreColorClass(score: number): string {
    77→    if (score >= 70) return "text-white";
    78→    if (score >= 50) return "text-[#D2D3D4]";
    79→    return "text-[#5D5C5B]";
    80→}
