    87→    const [projects, setProjects] = useState<Project[]>([]);
    88→    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    89→    const [searchQuery, setSearchQuery] = useState("");
    90→    const [activeFilters, setActiveFilters] = useState<Set<string>>(new Set());
    91→    const [sortBy, setSortBy] = useState<SortOption>("newest");
    92→    const [settingsProject, setSettingsProject] = useState<Project | null>(null);
    93→
    94→    useEffect(() => {
    95→        const currentIdea = localStorage.getItem("k3rn_active_project");
    96→        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");
    97→
    98→        if (currentIdea) {
    99→            const idea = JSON.parse(currentIdea);
   100→            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
   101→            if (!exists) {
   102→                const newProject: Project = {
   103→                    id: idea.id || crypto.randomUUID(),
   104→                    title: idea.title,
   105→                    text: idea.text || "",
   106→                    globalScore: idea.globalScore ?? idea.analysis?.viabilityScore,
