   124→                { id: "2", title: "NFT Patent Marketplace", text: "Marketplace NFT pour brevets industriels", globalScore: 38, recommendation: "KILL", confidenceLevel: "HIGH", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true },
