   143→    const sortLabels: Record<SortOption, string> = {
   144→        newest: d?.sortNewest || "Newest",
   145→        oldest: d?.sortOldest || "Oldest",
   146→        score_desc: d?.sortScoreDesc || "Score (high to low)",
   147→        score_asc: d?.sortScoreAsc || "Score (low to high)",
   148→        alpha: d?.sortAlpha || "A → Z",
