   153→            const q = searchQuery.toLowerCase();
   154→            const matchesSearch =
   155→                getProjectTitle(p).toLowerCase().includes(q) ||
   156→                p.text.toLowerCase().includes(q) ||
   157→                getProjectDecision(p).toLowerCase().includes(q);
